function withTimeout(promise,ms,label='Operation'){
 return Promise.race([
  promise,
  new Promise((_,reject)=>setTimeout(()=>reject(new Error(label+' timed out after '+Math.round(ms/1000)+' seconds.')),ms))
 ]);
}
function setCloudDiagnostic(message=''){
 const el=document.getElementById('cloudDiagnostic');if(el)el.textContent=message;
}
function showCloudRetry(show=true){document.getElementById('cloudRetryButton')?.classList.toggle('hidden',!show)}
async function retryCloudSync(){
 showCloudRetry(false);setCloudDiagnostic('Retrying connection…');
 await initCloudSync(true);
}

function isAppDataKey(key){
 return key.startsWith('mp_') || key==='currentWeek' || key==='trainingMode';
}

function buildBackupSnapshot(){
 const storage={};
 for(let i=0;i<localStorage.length;i++){
  const key=localStorage.key(i);
  if(isAppDataKey(key))storage[key]=localStorage.getItem(key);
 }
 return {
  version:APP_VERSION,
  saved_at:new Date().toISOString(),
  storage
 };
}

function meaningfulBackupCount(snapshot){
 if(!snapshot || !snapshot.storage)return 0;
 return Object.entries(snapshot.storage).filter(([key,value])=>{
  if(key==='currentWeek'||key==='trainingMode'||key==='mp_readiness_history')return false;
  if(value==null||value===''||value==='{}'||value==='[]')return false;
  if(key.startsWith('mp_week_')||key.startsWith('mp_mode_')){
   try{
    const parsed=JSON.parse(value);
    return Object.values(parsed).some(v=>v!==''&&v!==false&&v!=null);
   }catch{return true}
  }
  return true;
 }).length;
}

function setCloudStatus(message,state=''){
 const status=document.getElementById('cloudStatus');
 const dot=document.getElementById('cloudDot');
 if(status)status.textContent=message;
 if(dot)dot.className='syncDot'+(state?' '+state:'');
}

function showCloudUser(user){
 const signedOut=document.getElementById('cloudSignedOut');
 const signedIn=document.getElementById('cloudSignedIn');
 if(!signedOut||!signedIn)return;
 signedOut.classList.toggle('hidden',!!user);
 signedIn.classList.toggle('hidden',!user);
 if(user)document.getElementById('cloudUserEmail').textContent=user.email||'Signed-in account';
}

function setLastSync(value){
 const el=document.getElementById('cloudLastSync');
 if(!el)return;
 if(!value){el.textContent='Not synced yet';return}
 const date=new Date(value);
 el.textContent='Last cloud save: '+(isNaN(date)?value:date.toLocaleString());
}

function scheduleCloudSync(){
 if(cloudApplying||!cloudUser||!cloudAutoSyncReady)return;
 clearTimeout(cloudSyncTimer);
 setCloudStatus('Changes saved locally. Cloud sync pending…','busy');
 cloudSyncTimer=setTimeout(()=>cloudUpload(true),1800);
}

/* Watch all Marine Prep local-storage changes without interfering with Supabase auth storage. */
const nativeStorageSetItem=Storage.prototype.setItem;
Storage.prototype.setItem=function(key,value){
 nativeStorageSetItem.call(this,key,value);
 if(this===localStorage && isAppDataKey(String(key)) && !cloudApplying){
  nativeStorageSetItem.call(localStorage,'mpp_local_updated_at',new Date().toISOString());
  scheduleCloudSync();
 }
};

async function initCloudSync(forceRetry=false){
 cloudInitAttempt++;
 const attempt=cloudInitAttempt;
 showCloudRetry(false);
 setCloudDiagnostic('Connection attempt '+attempt+'…');
 if(!navigator.onLine){
  setCloudStatus('Offline. Data is saved locally.','busy');
  setCloudDiagnostic('Connect to the internet, then retry.');
  showCloudRetry(true);
  return;
 }
 if(!window.supabase || !window.supabase.createClient){
  setCloudStatus('Cloud library did not load. Local saves still work.','error');
  setCloudDiagnostic('The Supabase browser library was blocked or unavailable.');
  showCloudRetry(true);
  return;
 }
 try{
  if(!supabaseClient || forceRetry){
   supabaseClient=window.supabase.createClient(SUPABASE_URL,SUPABASE_PUBLISHABLE_KEY,{
    auth:{persistSession:true,detectSessionInUrl:true,autoRefreshToken:true}
   });
  }
  const result=await withTimeout(supabaseClient.auth.getSession(),12000,'Supabase session check');
  if(result.error)throw result.error;
  setCloudDiagnostic('Supabase connection established.');
  await withTimeout(handleCloudSession(result.data.session),15000,'Cloud backup check');
  if(!window.__mppAuthListenerAttached){
   window.__mppAuthListenerAttached=true;
   supabaseClient.auth.onAuthStateChange((_event,session)=>setTimeout(()=>handleCloudSession(session),0));
  }
 }catch(error){
  console.error(error);
  setCloudStatus('Cloud connection failed. Local saves still work.','error');
  setCloudDiagnostic(error.message||'Unknown cloud connection error.');
  showCloudRetry(true);
 }
}
async function handleCloudSession(session){
 cloudUser=session?.user||null;
 cloudAutoSyncReady=false;
 latestCloudRow=null;
 showCloudUser(cloudUser);
 if(!cloudUser){
  setCloudStatus('Not signed in. Data is saved only on this device.');
  setLastSync(null);
  return;
 }
 setCloudStatus('Checking your cloud backup…','busy');
 await reconcileCloudBackup();
}

function cloudCredentials(){
 return {
  email:(document.getElementById('cloudEmail')?.value||'').trim(),
  password:document.getElementById('cloudPassword')?.value||''
 };
}
function validateCloudCredentials(email,password){
 if(!email || !email.includes('@')){
  setCloudStatus('Enter a valid email address.','error');
  alert('Enter a valid email address.');
  return false;
 }
 if(password.length<8){
  setCloudStatus('Password must contain at least 8 characters.','error');
  alert('Use a password with at least 8 characters.');
  return false;
 }
 if(!supabaseClient){
  setCloudStatus('Cloud connection is not ready. Tap Retry cloud connection.','error');
  showCloudRetry(true);
  return false;
 }
 return true;
}
function cloudErrorMessage(error){
 if(!error)return 'Unknown error';
 if(typeof error==='string')return error;
 if(error.message)return error.message;
 if(error.error_description)return error.error_description;
 try{
  const text=JSON.stringify(error);
  return text==='{}'?'Supabase returned an unspecified authentication error.':text;
 }catch{return 'Unknown authentication error'}
}
function setAuthButtonsBusy(busy,label='Working…'){
 const signIn=document.getElementById('cloudSignInButton');
 const create=document.getElementById('cloudCreateButton');
 if(signIn){signIn.disabled=busy;signIn.textContent=busy&&label==='Signing in…'?label:'Sign in'}
 if(create){create.disabled=busy;create.textContent=busy&&label==='Creating…'?label:'Create account'}
}
async function cloudPasswordSignIn(){
 const {email,password}=cloudCredentials();
 if(!validateCloudCredentials(email,password))return;
 setAuthButtonsBusy(true,'Signing in…');
 setCloudStatus('Signing in…','busy');
 setCloudDiagnostic('');
 try{
  const {data,error}=await withTimeout(
   supabaseClient.auth.signInWithPassword({email,password}),
   15000,
   'Password sign-in'
  );
  if(error)throw error;
  if(!data?.session)throw new Error('No signed-in session was returned.');
  cloudUser=data.user||data.session.user;
  showCloudUser(cloudUser);
  document.getElementById('cloudPassword').value='';
  setCloudStatus('Signed in. Checking cloud backup…','busy');
  await reconcileCloudBackup();
 }catch(error){
  const message=cloudErrorMessage(error);
  console.error(error);
  setCloudStatus('Sign-in failed.','error');
  setCloudDiagnostic(message);
  showCloudRetry(error?.message?.includes('timed out'));
  alert(message);
 }finally{
  setAuthButtonsBusy(false);
 }
}
async function cloudCreateAccount(){
 const {email,password}=cloudCredentials();
 if(!validateCloudCredentials(email,password))return;
 if(!confirm('Create a Marine Prep Pro cloud account using this email?'))return;
 setAuthButtonsBusy(true,'Creating…');
 setCloudStatus('Creating account…','busy');
 setCloudDiagnostic('');
 try{
  const {data,error}=await withTimeout(
   supabaseClient.auth.signUp({email,password}),
   15000,
   'Account creation'
  );
  if(error)throw error;
  if(!data?.session){
   throw new Error('Account was created but Supabase did not sign it in. Confirm Email may still be enabled in Supabase.');
  }
  cloudUser=data.user||data.session.user;
  showCloudUser(cloudUser);
  document.getElementById('cloudPassword').value='';
  setCloudStatus('Account created. Creating cloud backup…','busy');
  await reconcileCloudBackup();
 }catch(error){
  const message=cloudErrorMessage(error);
  console.error(error);
  setCloudStatus('Account could not be created.','error');
  setCloudDiagnostic(message);
  showCloudRetry(error?.message?.includes('timed out'));
  if(/already registered|already been registered|user already exists/i.test(message)){
   alert('That email already has a Supabase account. Use Sign in with its existing password. If this was an old code-only test account with no password, delete that user under Supabase → Authentication → Users, then create the account again.');
  }else{
   alert(message);
  }
 }finally{
  setAuthButtonsBusy(false);
 }
}
async function cloudSignOut(){
 if(!supabaseClient)return;
 clearTimeout(cloudSyncTimer);
 cloudAutoSyncReady=false;
 const {error}=await supabaseClient.auth.signOut();
 if(error)alert(error.message);
}

async function fetchCloudBackup(){
 const request=supabaseClient
  .from('app_backups')
  .select('backup_data,app_version,updated_at')
  .eq('user_id',cloudUser.id)
  .maybeSingle();
 const {data,error}=await withTimeout(request,12000,'Cloud backup request');
 if(error)throw error;
 latestCloudRow=data||null;
 return latestCloudRow;
}

async function reconcileCloudBackup(){
 try{
  const row=await fetchCloudBackup();
  const local=buildBackupSnapshot();
  const localCount=meaningfulBackupCount(local);
  const cloudCount=meaningfulBackupCount(row?.backup_data);

  if(!row){
   setCloudStatus('Creating your first cloud backup…','busy');
   cloudAutoSyncReady=true;
   await cloudUpload(true);
   return;
  }

  setLastSync(row.updated_at);
  const localUpdated=Date.parse(localStorage.getItem('mpp_local_updated_at')||'')||0;
  const cloudUpdated=Date.parse(row.updated_at||row.backup_data?.saved_at||'')||0;

  if(localCount===0 && cloudCount>0){
   await applyCloudBackup(row.backup_data,false);
   return;
  }

  if(cloudCount>0 && cloudUpdated>localUpdated+5000){
   cloudAutoSyncReady=false;
   setCloudStatus('A newer cloud backup is available. Choose Restore or Back up this device.','busy');
   return;
  }

  cloudAutoSyncReady=true;
  setCloudStatus('Signed in and synced.','ok');
  if(localCount>0 && localUpdated>cloudUpdated+5000)await cloudUpload(true);
 }catch(error){
  console.error(error);
  setCloudStatus('Could not check the cloud backup. Local saves still work.','error');
 }
}

async function cloudUpload(silent=false){
 if(!cloudUser||!supabaseClient){
  if(!silent)alert('Sign in before backing up.');
  return;
 }
 try{
  clearTimeout(cloudSyncTimer);
  setCloudStatus('Saving to cloud…','busy');
  const snapshot=buildBackupSnapshot();
  const {data,error}=await supabaseClient
   .from('app_backups')
   .upsert({
    user_id:cloudUser.id,
    backup_data:snapshot,
    app_version:APP_VERSION,
    updated_at:snapshot.saved_at
   },{onConflict:'user_id'})
   .select('updated_at')
   .single();
  if(error)throw error;
  latestCloudRow={backup_data:snapshot,app_version:APP_VERSION,updated_at:data.updated_at};
  nativeStorageSetItem.call(localStorage,'mpp_local_updated_at',data.updated_at);
  cloudAutoSyncReady=true;
  setLastSync(data.updated_at);
  setCloudStatus('Saved to cloud.','ok');
  if(!silent)alert('This device’s training data is backed up.');
 }catch(error){
  console.error(error);
  setCloudStatus('Cloud save failed. Data remains saved locally.','error');
  if(!silent)alert(error.message||'Cloud save failed.');
 }
}

async function cloudRestore(confirmFirst=true){
 if(!cloudUser||!supabaseClient){
  alert('Sign in before restoring.');
  return;
 }
 try{
  setCloudStatus('Loading cloud backup…','busy');
  const row=await fetchCloudBackup();
  if(!row?.backup_data?.storage){
   setCloudStatus('No cloud backup exists yet.','error');
   alert('No cloud backup was found for this account.');
   return;
  }
  if(confirmFirst && !confirm('Replace this device’s Marine Prep data with the cloud backup?')){
   setCloudStatus('Restore cancelled.');
   return;
  }
  await applyCloudBackup(row.backup_data,false);
 }catch(error){
  console.error(error);
  setCloudStatus('Cloud restore failed.','error');
  alert(error.message||'Cloud restore failed.');
 }
}

async function applyCloudBackup(backup,confirmFirst=false){
 if(confirmFirst && !confirm('Replace this device’s Marine Prep data with the cloud backup?'))return;
 cloudApplying=true;
 try{
  const remove=[];
  for(let i=0;i<localStorage.length;i++){
   const key=localStorage.key(i);
   if(isAppDataKey(key))remove.push(key);
  }
  remove.forEach(key=>localStorage.removeItem(key));
  Object.entries(backup.storage||{}).forEach(([key,value])=>{
   if(isAppDataKey(key))nativeStorageSetItem.call(localStorage,key,value);
  });
  nativeStorageSetItem.call(localStorage,'mpp_local_updated_at',backup.saved_at||new Date().toISOString());
  currentWeek=Number(localStorage.getItem('currentWeek')||1);
  trainingMode=localStorage.getItem('trainingMode')||'normal';
  cloudAutoSyncReady=true;
  renderAll();
  setLastSync(latestCloudRow?.updated_at||backup.saved_at);
  setCloudStatus('Cloud backup restored.','ok');
  alert('Cloud backup restored to this device.');
 }finally{
  cloudApplying=false;
 }
}


function modeKey(){return trainingMode==='normal'?'normal_'+currentWeek:trainingMode+'_week_'+currentWeek}
function activePlan(){
 if(trainingMode==='normal')return DATA.weeks[currentWeek];
 return DATA.trainingModes[trainingMode].days;
}
function activeModeInfo(){
 if(trainingMode==='normal')return {label:'Normal week',description:'Following the scheduled Year 1 progression for Week '+currentWeek+'.'};
 const info=DATA.trainingModes[trainingMode]||{label:'Alternate week',description:'Alternate training schedule.'};
 return {
  ...info,
  description:info.description+' Progress is stored separately for Year 1 Week '+currentWeek+'.'
 };
}
function setTrainingMode(mode){
 trainingMode=mode;localStorage.setItem('trainingMode',mode);
 document.querySelectorAll('.modeSelect').forEach(s=>s.value=mode);
 renderAll();
}
function modeWeekKey(mode,w){
 return 'mp_mode_'+mode+'_week_'+Number(w||currentWeek);
}
function stateStorageKey(){
 return trainingMode==='normal'?'mp_week_'+currentWeek:modeWeekKey(trainingMode,currentWeek);
}
function wkKey(w){return 'mp_week_'+w}
function readStoredState(key){
 try{
  const parsed=JSON.parse(localStorage.getItem(key)||'{}');
  return parsed&&typeof parsed==='object'&&!Array.isArray(parsed)?parsed:{};
 }catch(error){
  console.warn('Could not read workout state:',key,error);
  return {};
 }
}
function migrateLegacyModeState(mode,w){
 const scopedKey=modeWeekKey(mode,w);
 const scopedRaw=localStorage.getItem(scopedKey);
 if(scopedRaw!==null)return readStoredState(scopedKey);

 const legacyKey='mp_mode_'+mode;
 const legacyRaw=localStorage.getItem(legacyKey);
 const markerKey='mp_mode_'+mode+'_legacy_week';
 const migratedWeek=Number(localStorage.getItem(markerKey)||0);

 // Assign the old shared progress to only the first selected week after upgrading.
 // Other weeks begin clean instead of inheriting the same checkmarks.
 if(legacyRaw!==null && !migratedWeek){
  const legacyState=readStoredState(legacyKey);
  localStorage.setItem(scopedKey,JSON.stringify(legacyState));
  localStorage.setItem(markerKey,String(w));
  return legacyState;
 }
 return {};
}
function getWeekState(w){
 const week=Number(w||currentWeek);
 if(trainingMode==='normal')return readStoredState(wkKey(week));
 return migrateLegacyModeState(trainingMode,week);
}
function putWeekState(w,s){
 const week=Number(w||currentWeek);
 const key=trainingMode==='normal'?wkKey(week):modeWeekKey(trainingMode,week);
 localStorage.setItem(key,JSON.stringify(s));
}
function progressHistory(){return JSON.parse(localStorage.getItem('mp_progress')||'[]')}

