function renderRunSummary(){
 const el=document.getElementById('runSummary');if(!el)return;const rows=getJSON('mp_run_logs',[]),recent=rows.slice(-7),miles=recent.reduce((a,b)=>a+Number(b.miles||0),0),last=rows[rows.length-1];
 let pace='—';if(last)pace=(parseClock(last.time)/last.miles).toFixed(1)+' min/mi';const prev=rows.slice(-14,-7).reduce((a,b)=>a+Number(b.miles||0),0),jump=prev>0&&miles>prev*1.1,history=rows.map((x,i)=>({...x,_index:i})).slice(-10).reverse();
 el.innerHTML=`<div class="grid"><div class="metric"><label>Recent 7 logged runs</label><strong>${miles.toFixed(1)} mi</strong></div><div class="metric"><label>Latest pace</label><strong>${pace}</strong></div><div class="metric"><label>25:00 3-mile target pace</label><strong>8.3 min/mi</strong></div></div>${jump?'<div class="commandAlert detailWarn">Mileage increased more than 10% compared with the previous seven logged runs. Do not automatically add more.</div>':''}<h3 style="margin-top:14px">Saved runs</h3>${history.length?history.map(x=>`<div class="editableLog" onclick="editRunLog(${x._index})"><strong>${x.date}</strong><div class="small muted">${x.miles} mi · ${x.time} · RPE ${x.effort||'—'}</div><div class="editHint">Tap to edit</div></div>`).join(''):'<div class="small muted">No runs saved.</div>'}`;
}
let runTimerHandle=null,runTimerPhase=0,runTimerLeft=0;
function startRunInterval(){
 stopRunInterval();runTimerPhase=0;runTimerLeft=60;
 document.getElementById('runTimerStatus').textContent='RUN · 1:00';
 runTimerHandle=setInterval(()=>{runTimerLeft--;if(runTimerLeft<=0){runTimerPhase=1-runTimerPhase;runTimerLeft=runTimerPhase?90:60}
 document.getElementById('runTimerStatus').textContent=(runTimerPhase?'WALK':'RUN')+' · '+Math.floor(runTimerLeft/60)+':'+String(runTimerLeft%60).padStart(2,'0')},1000);
}
function stopRunInterval(){if(runTimerHandle)clearInterval(runTimerHandle);runTimerHandle=null;const e=document.getElementById('runTimerStatus');if(e)e.textContent='Timer stopped.'}

